// security/EncryptionService.js
import CryptoJS from 'crypto-js';
import EncryptedStorage from 'react-native-encrypted-storage';
import * as Keychain from 'react-native-keychain';
import { v4 as uuidv4 } from 'uuid';

class EncryptionService {
  constructor() {
    this._encryptionKey = null;
    this._initialized = false;
  }

  async initialize() {
    if (this._initialized) return;

    try {
      const credentials = await Keychain.getGenericPassword({
        service: 'payment_encryption_key',
      });

      if (credentials) {
        this._encryptionKey = credentials.password;
      } else {
        this._encryptionKey = uuidv4() + '-' + Date.now().toString(36);
        await Keychain.setGenericPassword('payment_key', this._encryptionKey, {
          service: 'payment_encryption_key',
          accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_ANY_OR_DEVICE_PASSCODE,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        });
      }

      this._initialized = true;
    } catch (error) {
      console.error('EncryptionService initialization failed:', error);
      throw new PaymentSecurityError('Failed to initialize encryption service');
    }
  }

  encrypt(data) {
    if (!this._initialized) {
      throw new PaymentSecurityError('EncryptionService not initialized');
    }

    const jsonString = typeof data === 'string' ? data : JSON.stringify(data);
    const iv = CryptoJS.lib.WordArray.random(16);
    const encrypted = CryptoJS.AES.encrypt(jsonString, this._encryptionKey, {
      iv: iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });

    return {
      ciphertext: encrypted.toString(),
      iv: iv.toString(CryptoJS.enc.Hex),
      timestamp: Date.now(),
      checksum: CryptoJS.SHA256(jsonString).toString(),
    };
  }

  decrypt(encryptedData) {
    if (!this._initialized) {
      throw new PaymentSecurityError('EncryptionService not initialized');
    }

    try {
      const decrypted = CryptoJS.AES.decrypt(
        encryptedData.ciphertext,
        this._encryptionKey,
        {
          iv: CryptoJS.enc.Hex.parse(encryptedData.iv),
          mode: CryptoJS.mode.CBC,
          padding: CryptoJS.pad.Pkcs7,
        }
      );

      const decryptedString = decrypted.toString(CryptoJS.enc.Utf8);

      // Verify checksum
      const checksum = CryptoJS.SHA256(decryptedString).toString();
      if (checksum !== encryptedData.checksum) {
        throw new PaymentSecurityError('Data integrity check failed');
      }

      return JSON.parse(decryptedString);
    } catch (error) {
      if (error instanceof PaymentSecurityError) throw error;
      throw new PaymentSecurityError('Decryption failed: ' + error.message);
    }
  }

  async secureStore(key, data) {
    const encrypted = this.encrypt(data);
    await EncryptedStorage.setItem(key, JSON.stringify(encrypted));
  }

  async secureRetrieve(key) {
    const stored = await EncryptedStorage.getItem(key);
    if (!stored) return null;
    return this.decrypt(JSON.parse(stored));
  }

  async secureDelete(key) {
    await EncryptedStorage.removeItem(key);
  }

  sanitizeSensitiveData(data) {
    const sanitized = { ...data };
    const sensitiveFields = [
      'cardNumber',
      'cvv',
      'pin',
      'password',
      'securityCode',
      'accountNumber',
      'routingNumber',
    ];

    sensitiveFields.forEach((field) => {
      if (sanitized[field]) {
        const value = sanitized[field].toString();
        sanitized[field] =
          '****' + value.substring(Math.max(0, value.length - 4));
      }
    });

    return sanitized;
  }

  generateTransactionId() {
    return `txn_${uuidv4().replace(/-/g, '')}_${Date.now().toString(36)}`;
  }

  generateIdempotencyKey() {
    return `idem_${uuidv4()}`;
  }
}

export const encryptionService = new EncryptionService();

