// errors/PaymentErrors.js
export class PaymentError extends Error {
  constructor(message, code, details = {}) {
    super(message);
    this.name = 'PaymentError';
    this.code = code;
    this.details = details;
    this.timestamp = new Date().toISOString();
  }
}

export class PaymentSecurityError extends PaymentError {
  constructor(message, details = {}) {
    super(message, 'SECURITY_ERROR', details);
    this.name = 'PaymentSecurityError';
  }
}

export class PaymentValidationError extends PaymentError {
  constructor(message, details = {}) {
    super(message, 'VALIDATION_ERROR', details);
    this.name = 'PaymentValidationError';
  }
}

export class PaymentNetworkError extends PaymentError {
  constructor(message, details = {}) {
    super(message, 'NETWORK_ERROR', details);
    this.name = 'PaymentNetworkError';
  }
}

export class PaymentProviderError extends PaymentError {
  constructor(message, provider, details = {}) {
    super(message, 'PROVIDER_ERROR', { ...details, provider });
    this.name = 'PaymentProviderError';
  }
}

