// validation/PaymentValidator.js
export class PaymentValidator {
  static validateAmount(amount, currency = 'USD') {
    if (typeof amount !== 'number' || isNaN(amount)) {
      throw new PaymentValidationError('Amount must be a valid number');
    }
    if (amount <= 0) {
      throw new PaymentValidationError('Amount must be greater than zero');
    }
    if (amount > 999999.99) {
      throw new PaymentValidationError('Amount exceeds maximum allowed');
    }

    const currencyDecimals = {
      USD: 2,
      EUR: 2,
      GBP: 2,
      JPY: 0,
      KRW: 0,
    };

    const decimals = currencyDecimals[currency] ?? 2;
    const multiplier = Math.pow(10, decimals);
    const roundedAmount = Math.round(amount * multiplier) / multiplier;

    return roundedAmount;
  }

  static validateCurrency(currency) {
    const supportedCurrencies = [
      'USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD', 'CHF', 'CNY', 'KRW', 'INR',
    ];
    if (!supportedCurrencies.includes(currency)) {
      throw new PaymentValidationError(
        `Unsupported currency: ${currency}. Supported: ${supportedCurrencies.join(', ')}`
      );
    }
    return true;
  }

  static validateProductId(productId) {
    if (!productId || typeof productId !== 'string') {
      throw new PaymentValidationError('Product ID is required');
    }
    if (productId.length > 150) {
      throw new PaymentValidationError('Product ID exceeds maximum length');
    }
    if (!/^[a-zA-Z0-9._-]+$/.test(productId)) {
      throw new PaymentValidationError('Product ID contains invalid characters');
    }
    return true;
  }

  static validateEmail(email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      throw new PaymentValidationError('Invalid email address');
    }
    return true;
  }

  static validateCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s|-/g, '');
    if (!/^\d{13,19}$/.test(cleaned)) {
      throw new PaymentValidationError('Invalid card number format');
    }

    // Luhn algorithm
    let sum = 0;
    let isEven = false;
    for (let i = cleaned.length - 1; i >= 0; i--) {
      let digit = parseInt(cleaned[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }

    if (sum % 10 !== 0) {
      throw new PaymentValidationError('Invalid card number');
    }

    return true;
  }

  static detectCardBrand(cardNumber) {
    const cleaned = cardNumber.replace(/\s|-/g, '');
    const patterns = {
      visa: /^4/,
      mastercard: /^5[1-5]|^2[2-7]/,
      amex: /^3[47]/,
      discover: /^6(?:011|5)/,
      diners: /^3(?:0[0-5]|[68])/,
      jcb: /^(?:2131|1800|35)/,
    };

    for (const [brand, pattern] of Object.entries(patterns)) {
      if (pattern.test(cleaned)) return brand;
    }
    return 'unknown';
  }

  static validatePaymentRequest(request) {
    const errors = [];

    if (!request.amount) errors.push('Amount is required');
    if (!request.currency) errors.push('Currency is required');
    if (!request.provider) errors.push('Payment provider is required');

    try {
      if (request.amount) this.validateAmount(request.amount, request.currency);
    } catch (e) {
      errors.push(e.message);
    }

    try {
      if (request.currency) this.validateCurrency(request.currency);
    } catch (e) {
      errors.push(e.message);
    }

    if (errors.length > 0) {
      throw new PaymentValidationError('Validation failed', { errors });
    }

    return true;
  }
}

