// services/IAPService.js
import { Platform } from 'react-native';
import * as RNIap from 'react-native-iap';

class IAPService {
  constructor() {
    this._initialized = false;
    this._products = new Map();
    this._subscriptions = new Map();
    this._purchaseListeners = [];
    this._purchaseUpdateSubscription = null;
    this._purchaseErrorSubscription = null;
  }

  async initialize() {
    if (this._initialized) return;

    try {
      const result = await RNIap.initConnection();
      console.log('IAP Connection initialized:', result);

      if (Platform.OS === 'android') {
        await RNIap.flushFailedPurchasesCachedAsPendingAndroid();
      }

      this._setupListeners();
      this._initialized = true;
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to initialize IAP: ' + error.message,
        PaymentProvider.IAP
      );
    }
  }

  _setupListeners() {
    this._purchaseUpdateSubscription = RNIap.purchaseUpdatedListener(
      async (purchase) => {
        const receipt = purchase.transactionReceipt;

        if (receipt) {
          try {
            // Validate receipt server-side
            const isValid = await this._validateReceipt(purchase);

            if (isValid) {
              // Acknowledge/finish the purchase
              if (Platform.OS === 'android') {
                if (!purchase.isAcknowledgedAndroid) {
                  await RNIap.acknowledgePurchaseAndroid({
                    token: purchase.purchaseToken,
                  });
                }
              }

              await RNIap.finishTransaction({ purchase, isConsumable: false });

              this._notifyListeners({
                type: 'PURCHASE_SUCCESS',
                purchase: this._normalizePurchase(purchase),
              });
            } else {
              this._notifyListeners({
                type: 'PURCHASE_FAILED',
                error: 'Receipt validation failed',
                purchase: this._normalizePurchase(purchase),
              });
            }
          } catch (error) {
            this._notifyListeners({
              type: 'PURCHASE_FAILED',
              error: error.message,
              purchase: this._normalizePurchase(purchase),
            });
          }
        }
      }
    );

    this._purchaseErrorSubscription = RNIap.purchaseErrorListener((error) => {
      this._notifyListeners({
        type: 'PURCHASE_ERROR',
        error: {
          code: error.code,
          message: error.message,
          debugMessage: error.debugMessage,
        },
      });
    });
  }

  _normalizePurchase(purchase) {
    return {
      transactionId:
        purchase.transactionId || purchase.orderId || purchase.purchaseToken,
      productId: purchase.productId,
      transactionDate: purchase.transactionDate,
      transactionReceipt: purchase.transactionReceipt,
      purchaseToken: purchase.purchaseToken,
      platform: Platform.OS,
      originalTransactionId:
        Platform.OS === 'ios'
          ? purchase.originalTransactionIdentifierIOS
          : undefined,
    };
  }

  async _validateReceipt(purchase) {
    try {
      // Server-side receipt validation
      const response = await fetch(
        `${API_BASE_URL}/payments/validate-receipt`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${await this._getAuthToken()}`,
          },
          body: JSON.stringify({
            receipt: purchase.transactionReceipt,
            productId: purchase.productId,
            platform: Platform.OS,
            transactionId: purchase.transactionId,
            purchaseToken: purchase.purchaseToken,
          }),
        }
      );

      if (!response.ok) {
        throw new Error('Receipt validation request failed');
      }

      const result = await response.json();
      return result.valid === true;
    } catch (error) {
      console.error('Receipt validation error:', error);
      // In production, you might want to be more strict here
      return false;
    }
  }

  async _getAuthToken() {
    return await encryptionService.secureRetrieve('auth_token');
  }

  async loadProducts(productIds) {
    this._ensureInitialized();
    PaymentValidator.validateProductId;

    try {
      const products = await RNIap.getProducts({ skus: productIds });

      products.forEach((product) => {
        this._products.set(product.productId, {
          id: product.productId,
          title: product.title,
          description: product.description,
          price: product.price,
          localizedPrice: product.localizedPrice,
          currency: product.currency,
          type: ProductType.CONSUMABLE,
          platform: Platform.OS,
          raw: product,
        });
      });

      return Array.from(this._products.values());
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to load products: ' + error.message,
        PaymentProvider.IAP
      );
    }
  }

  async loadSubscriptions(subscriptionIds) {
    this._ensureInitialized();

    try {
      const subscriptions = await RNIap.getSubscriptions({
        skus: subscriptionIds,
      });

      subscriptions.forEach((sub) => {
        this._subscriptions.set(sub.productId, {
          id: sub.productId,
          title: sub.title,
          description: sub.description,
          price: sub.price,
          localizedPrice: sub.localizedPrice,
          currency: sub.currency,
          subscriptionPeriod:
            Platform.OS === 'ios'
              ? sub.subscriptionPeriodUnitIOS
              : sub.subscriptionPeriodAndroid,
          introductoryPrice: sub.introductoryPrice,
          freeTrialPeriod:
            Platform.OS === 'android'
              ? sub.freeTrialPeriodAndroid
              : sub.introductoryPriceSubscriptionPeriodIOS,
          type: ProductType.SUBSCRIPTION,
          platform: Platform.OS,
          raw: sub,
        });
      });

      return Array.from(this._subscriptions.values());
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to load subscriptions: ' + error.message,
        PaymentProvider.IAP
      );
    }
  }

  async purchaseProduct(productId, isConsumable = false) {
    this._ensureInitialized();
    PaymentValidator.validateProductId(productId);

    try {
      const purchase = await RNIap.requestPurchase({
        sku: productId,
        andDangerouslyFinishTransactionAutomaticallyIOS: false,
      });

      if (isConsumable && purchase) {
        await RNIap.finishTransaction({ purchase, isConsumable: true });
      }

      return this._normalizePurchase(purchase);
    } catch (error) {
      if (error.code === 'E_USER_CANCELLED') {
        throw new PaymentError('Purchase cancelled by user', 'USER_CANCELLED');
      }
      throw new PaymentProviderError(
        'Purchase failed: ' + error.message,
        PaymentProvider.IAP,
        { code: error.code }
      );
    }
  }

  async purchaseSubscription(subscriptionId, offerToken) {
    this._ensureInitialized();
    PaymentValidator.validateProductId(subscriptionId);

    try {
      const purchaseParams = {
        sku: subscriptionId,
        andDangerouslyFinishTransactionAutomaticallyIOS: false,
      };

      if (Platform.OS === 'android' && offerToken) {
        purchaseParams.subscriptionOffers = [
          { sku: subscriptionId, offerToken },
        ];
      }

      const purchase = await RNIap.requestSubscription(purchaseParams);
      return this._normalizePurchase(purchase);
    } catch (error) {
      if (error.code === 'E_USER_CANCELLED') {
        throw new PaymentError(
          'Subscription cancelled by user',
          'USER_CANCELLED'
        );
      }
      throw new PaymentProviderError(
        'Subscription purchase failed: ' + error.message,
        PaymentProvider.IAP,
        { code: error.code }
      );
    }
  }

  async getAvailablePurchases() {
    this._ensureInitialized();

    try {
      const purchases = await RNIap.getAvailablePurchases();
      return purchases.map((p) => this._normalizePurchase(p));
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to get available purchases: ' + error.message,
        PaymentProvider.IAP
      );
    }
  }

  async restorePurchases() {
    return this.getAvailablePurchases();
  }

  addPurchaseListener(listener) {
    this._purchaseListeners.push(listener);
    return () => {
      this._purchaseListeners = this._purchaseListeners.filter(
        (l) => l !== listener
      );
    };
  }

  _notifyListeners(event) {
    this._purchaseListeners.forEach((listener) => {
      try {
        listener(event);
      } catch (error) {
        console.error('Purchase listener error:', error);
      }
    });
  }

  _ensureInitialized() {
    if (!this._initialized) {
      throw new PaymentProviderError(
        'IAP Service not initialized. Call initialize() first.',
        PaymentProvider.IAP
      );
    }
  }

  async cleanup() {
    if (this._purchaseUpdateSubscription) {
      this._purchaseUpdateSubscription.remove();
    }
    if (this._purchaseErrorSubscription) {
      this._purchaseErrorSubscription.remove();
    }
    await RNIap.endConnection();
    this._initialized = false;
    this._products.clear();
    this._subscriptions.clear();
    this._purchaseListeners = [];
  }
}

export const iapService = new IAPService();

