// services/StripeService.js
import { StripeProvider, useStripe } from '@stripe/stripe-react-native';

const API_BASE_URL = 'https://api.yourapp.com/v1';

class StripeService {
  constructor() {
    this._initialized = false;
    this._publishableKey = null;
    this._merchantId = null;
  }

  async initialize(config) {
    try {
      this._publishableKey = config.publishableKey;
      this._merchantId = config.merchantId;
      this._initialized = true;
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to initialize Stripe: ' + error.message,
        PaymentProvider.STRIPE
      );
    }
  }

  getPublishableKey() {
    return this._publishableKey;
  }

  getMerchantId() {
    return this._merchantId;
  }

  async createPaymentIntent(amount, currency, metadata = {}) {
    this._ensureInitialized();
    PaymentValidator.validateAmount(amount, currency);
    PaymentValidator.validateCurrency(currency);

    try {
      const idempotencyKey = encryptionService.generateIdempotencyKey();

      const response = await fetch(
        `${API_BASE_URL}/payments/create-intent`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${await this._getAuthToken()}`,
            'Idempotency-Key': idempotencyKey,
          },
          body: JSON.stringify({
            amount: Math.round(amount * 100), // Convert to cents
            currency: currency.toLowerCase(),
            metadata: {
              ...metadata,
              platform: Platform.OS,
              appVersion: '1.0.0',
            },
          }),
        }
      );

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to create payment intent');
      }

      const data = await response.json();
      return {
        clientSecret: data.clientSecret,
        paymentIntentId: data.paymentIntentId,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
      };
    } catch (error) {
      if (error instanceof PaymentError) throw error;
      throw new PaymentProviderError(
        'Failed to create payment intent: ' + error.message,
        PaymentProvider.STRIPE
      );
    }
  }

  async confirmPayment(clientSecret, paymentMethodData) {
    this._ensureInitialized();

    try {
      // This will be called from the React component using the Stripe hook
      return { clientSecret, paymentMethodData };
    } catch (error) {
      throw new PaymentProviderError(
        'Payment confirmation failed: ' + error.message,
        PaymentProvider.STRIPE
      );
    }
  }

  async createSetupIntent() {
    this._ensureInitialized();

    try {
      const response = await fetch(
        `${API_BASE_URL}/payments/create-setup-intent`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${await this._getAuthToken()}`,
          },
        }
      );

      if (!response.ok) {
        throw new Error('Failed to create setup intent');
      }

      return await response.json();
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to create setup intent: ' + error.message,
        PaymentProvider.STRIPE
      );
    }
  }

  async getSavedPaymentMethods() {
    this._ensureInitialized();

    try {
      const response = await fetch(
        `${API_BASE_URL}/payments/payment-methods`,
        {
          headers: {
            Authorization: `Bearer ${await this._getAuthToken()}`,
          },
        }
      );

      if (!response.ok) {
        throw new Error('Failed to fetch payment methods');
      }

      const data = await response.json();
      return data.paymentMethods.map((pm) => ({
        id: pm.id,
        type: pm.type,
        card: pm.card
          ? {
              brand: pm.card.brand,
              last4: pm.card.last4,
              expMonth: pm.card.exp_month,
              expYear: pm.card.exp_year,
            }
          : null,
        isDefault: pm.isDefault,
      }));
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to get payment methods: ' + error.message,
        PaymentProvider.STRIPE
      );
    }
  }

  async deletePaymentMethod(paymentMethodId) {
    this._ensureInitialized();

    try {
      const response = await fetch(
        `${API_BASE_URL}/payments/payment-methods/${paymentMethodId}`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${await this._getAuthToken()}`,
          },
        }
      );

      if (!response.ok) {
        throw new Error('Failed to delete payment method');
      }

      return true;
    } catch (error) {
      throw new PaymentProviderError(
        'Failed to delete payment method: ' + error.message,
        PaymentProvider.STRIPE
      );
    }
  }

  async _getAuthToken() {
    return await encryptionService.secureRetrieve('auth_token');
  }

  _ensureInitialized() {
    if (!this._initialized) {
      throw new PaymentProviderError(
        'Stripe Service not initialized',
        PaymentProvider.STRIPE
      );
    }
  }
}

