// services/DigitalWalletService.js
import { Platform } from 'react-native';

class DigitalWalletService {
  constructor() {
    this._initialized = false;
  }

  async initialize() {
    this._initialized = true;
  }

  async isApplePayAvailable() {
    if (Platform.OS !== 'ios') return false;

    try {
      // Using Stripe's Apple Pay check
      const { isApplePaySupported } = require('@stripe/stripe-react-native');
      return await isApplePaySupported();
    } catch (error) {
      console.error('Apple Pay availability check failed:', error);
      return false;
    }
  }

  async isGooglePayAvailable() {
    if (Platform.OS !== 'android') return false;

    try {
      const { isGooglePaySupported } = require('@stripe/stripe-react-native');
      return await isGooglePaySupported({ testEnv: __DEV__ });
    } catch (error) {
      console.error('Google Pay availability check failed:', error);
      return false;
    }
  }

  async getAvailableWallets() {
    const wallets = [];

    if (await this.isApplePayAvailable()) {
      wallets.push({
        type: PaymentProvider.APPLE_PAY,
        name: 'Apple Pay',
        icon: 'apple-pay',
      });
    }

    if (await this.isGooglePayAvailable()) {
      wallets.push({
        type: PaymentProvider.GOOGLE_PAY,
        name: 'Google Pay',
        icon: 'google-pay',
      });
    }

    return wallets;
  }

  async processApplePayPayment(amount, currency, merchantName) {
    if (Platform.OS !== 'ios') {
      throw new PaymentProviderError(
        'Apple Pay is only available on iOS',
        PaymentProvider.APPLE_PAY
      );
    }

    PaymentValidator.validateAmount(amount, currency);
    PaymentValidator.validateCurrency(currency);

    try {
      const { presentApplePay, confirmApplePayPayment } =
        require('@stripe/stripe-react-native');

      const { error: presentError } = await presentApplePay({
        cartItems: [
          {
            label: merchantName || 'Total',
            amount: amount.toFixed(2),
            paymentType: 'Immediate',
          },
        ],
        country: 'US',
        currency: currency,
      });

      if (presentError) {
        throw new Error(presentError.message);
      }

      // Create payment intent on server
      const paymentIntent = await stripeService.createPaymentIntent(
        amount,
        currency,
        { wallet: 'apple_pay' }
      );

      const { error: confirmError } = await confirmApplePayPayment(
        paymentIntent.clientSecret
      );

      if (confirmError) {
        throw new Error(confirmError.message);
      }

      return {
        transactionId: paymentIntent.paymentIntentId,
        status: TransactionStatus.COMPLETED,
        provider: PaymentProvider.APPLE_PAY,
        amount,
        currency,
      };
    } catch (error) {
      if (error instanceof PaymentError) throw error;
      throw new PaymentProviderError(
        'Apple Pay payment failed: ' + error.message,
        PaymentProvider.APPLE_PAY
      );
    }
  }

  async processGooglePayPayment(amount, currency) {
    if (Platform.OS !== 'android') {
      throw new PaymentProviderError(
        'Google Pay is only available on Android',
        PaymentProvider.GOOGLE_PAY
      );
    }

    PaymentValidator.validateAmount(amount, currency);
    PaymentValidator.validateCurrency(currency);

    try {
      const { initGooglePay, presentGooglePay } =
        require('@stripe/stripe-react-native');

      const { error: initError } = await initGooglePay({
        testEnv: __DEV__,
        merchantName: 'Your App Name',
        countryCode: 'US',
        billingAddressConfig: {
          format: 'FULL',
          isPhoneNumberRequired: false,
          isRequired: false,
        },
        existingPaymentMethodRequired: false,
        isEmailRequired: false,
      });

      if (initError) {
        throw new Error(initError.message);
      }

      // Create payment intent
      const paymentIntent = await stripeService.createPaymentIntent(
        amount,
        currency,
        { wallet: 'google_pay' }
      );

      const { error: payError } = await presentGooglePay({
        clientSecret: paymentIntent.clientSecret,
        forSetupIntent: false,
        currencyCode: currency,
      });

      if (payError) {
        throw new Error(payError.message);
      }

      return {
        transactionId: paymentIntent.paymentIntentId,
        status: TransactionStatus.COMPLETED,
        provider: PaymentProvider.GOOGLE_PAY,
        amount,
        currency,
      };
    } catch (error) {
      if (error instanceof PaymentError) throw error;
      throw new PaymentProviderError(
        'Google Pay payment failed: ' + error.message,
        PaymentProvider.GOOGLE_PAY
      );
    }
  }

  _ensureInitialized() {
    if (!this._initialized) {
      throw new PaymentProviderError(
        'Digital Wallet Service not initialized',
        'DIGITAL_WALLET'
      );
    }
  }
}

export const digitalWalletService = new DigitalWalletService();

// ============================================
// 9. Transaction Manager
// ============================================

// services/TransactionManager.js
class TransactionManager {
  constructor() {
    this._transactions = new Map();
    this._listeners = [];
    this._retryConfig = {
      maxRetries: 3,
      baseDelay: 1000,
      maxDelay: 10000,
    };
  }

  async recordTransaction(transaction) {
    const enrichedTransaction = {
      ...transaction,
      id: transaction.id || encryptionService.generateTransactionId(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      retryCount: 0,
    };

    this._transactions.set(enrichedTransaction.id, enrichedTransaction);

    // Persist to encrypted storage
    await this._persistTransaction(enrichedTransaction);

    // Sync with server
    await this._syncTransaction(enrichedTransaction);

    this._notifyListeners('TRANSACTION_RECORDED', enrichedTransaction);

    return enrichedTransaction;
  }

  async updateTransactionStatus(transactionId, status, details = {}) {
    const transaction = this._transactions.get(transactionId);
    if (!transaction) {
      throw new PaymentError('Transaction not found', 'NOT_FOUND');
    }

    const updatedTransaction = {
      ...transaction,
      status,
      updatedAt: new Date().toISOString(),
      statusHistory: [
        ...(transaction.statusHistory || []),
        {
          status,
          timestamp: new Date().toISOString(),
          details,
        },
      ],
    };

    this._transactions.set(transactionId, updatedTransaction);
    await this._persistTransaction(updatedTransaction);

    this._notifyListeners('TRANSACTION_UPDATED', updatedTransaction);

    return updatedTransaction;
  }

  async getTransaction(transactionId) {
    let transaction = this._transactions.get(transactionId);

    if (!transaction) {
      // Try to load from encrypted storage
      transaction = await encryptionService.secureRetrieve(
        `txn_${transactionId}`
      );
      if (transaction) {
        this._transactions.set(transactionId, transaction);
      }
    }

    return transaction || null;
  }

  async getTransactionHistory(filters = {}) {
    const allTransactions = Array.from(this._transactions.values());

    let filtered = allTransactions;

    if (filters.status) {
      filtered = filtered.filter((t) => t.status === filters.status);
    }

    if (filters.provider) {
      filtered = filtered.filter((t) => t.provider === filters.provider);
    }

    if (filters.startDate) {
      filtered = filtered.filter(
        (t) => new Date(t.createdAt) >= new Date(filters.startDate)
      );
    }

    if (filters.endDate) {
      filtered = filtered.filter(
        (t) => new Date(t.createdAt) <= new Date(filters.endDate)
      );
    }

    // Sort by date descending
    filtered.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

    if (filters.limit) {
      filtered = filtered.slice(0, filters.limit);
    }

    return filtered;
  }

  async retryFailedTransaction(transactionId) {
    const transaction = await this.getTransaction(transactionId);
    if (!transaction) {
      throw new PaymentError('Transaction not found', 'NOT_FOUND');
    }

    if (transaction.status !== TransactionStatus.FAILED) {
      throw new PaymentError(
        'Only failed transactions can be retried',
        'INVALID_STATE'
      );
    }

    if (transaction.retryCount >= this._retryConfig.maxRetries) {
      throw new PaymentError(
        'Maximum retry attempts exceeded',
        'MAX_RETRIES_EXCEEDED'
      );
    }

    const delay = Math.min(
      this._retryConfig.baseDelay *
        Math.pow(2, transaction.retryCount),
      this._retryConfig.maxDelay
    );

    await new Promise((resolve) => setTimeout(resolve, delay));

    const updatedTransaction = {
      ...transaction,
      retryCount: transaction.retryCount + 1,
      status: TransactionStatus.PENDING,
      updatedAt: new Date().toISOString(),
    };

    this._transactions.set(transactionId, updatedTransaction);
    await this._persistTransaction(updatedTransaction);

    return updatedTransaction;
  }

  async _persistTransaction(transaction) {
    try {
      // Sanitize before storing
      const sanitized = encryptionService.sanitizeSensitiveData(transaction);
      await encryptionService.secureStore(`txn_${transaction.id}`, sanitized);

      // Update transaction index
      const index =
        (await encryptionService.secureRetrieve('txn_index')) || [];
      if (!index.includes(transaction.id)) {
        index.push(transaction.id);
        await encryptionService.secureStore('txn_index', index);
      }
    } catch (error) {
      console.error('Failed to persist transaction:', error);
    }
  }

  async _syncTransaction(transaction) {
    try {
      const authToken = await encryptionService.secureRetrieve('auth_token');
      if (!authToken) return;

      await fetch(`${API_BASE_URL}/payments/transactions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${authToken}`,
        },
        body: JSON.stringify(
          encryptionService.sanitizeSensitiveData(transaction)
        ),
      });
    } catch (error) {
      console.error('Failed to sync transaction:', error);
      // Queue for later sync
      await this._queueForSync(transaction.id);
    }
  }

  async _queueForSync(transactionId) {
    const syncQueue =
      (await encryptionService.secureRetrieve('sync_queue')) || [];
    if (!syncQueue.includes(transactionId)) {
      syncQueue.push(transactionId);
      await encryptionService.secureStore('sync_queue', syncQueue);
    }
  }

  async processSyncQueue() {
    const syncQueue =
      (await encryptionService.secureRetrieve('sync_queue')) || [];

    for (const transactionId of syncQueue) {
      try {
        const transaction = await this.getTransaction(transactionId);
        if (transaction) {
          await this._syncTransaction(transaction);
          const updatedQueue = syncQueue.filter((id) => id !== transactionId);
          await encryptionService.secureStore('sync_queue', updatedQueue);
        }
      } catch (error) {
        console.error(`Failed to sync transaction ${transactionId}:`, error);
      }
    }
  }

  addListener(listener) {
    this._listeners.push(listener);
    return () => {
      this._listeners = this._listeners.filter((l) => l !== listener);
    };
  }

  _notifyListeners(event, data) {
    this._listeners.forEach((listener) => {
      try {
        listener({ event, data, timestamp: new Date().toISOString() });
      } catch (error) {
        console.error('Transaction listener error:', error);
      }
    });
  }

  async loadTransactionHistory() {
    try {
      const index =
        (await encryptionService.secureRetrieve('txn_index')) || [];
      for (const txnId of index) {
        if (!this._transactions.has(txnId)) {
          const txn = await encryptionService.secureRetrieve(`txn_${txnId}`);
          if (txn) {
            this._transactions.set(txnId, txn);
          }
        }
      }
    } catch (error) {
      console.error('Failed to load transaction history:', error);
    }
  }
}

export const transactionManager = new TransactionManager();

// ============================================
// 10. Payment State Management (Zustand Store)
// ============================================

// store/paymentStore.js
import { create } from 'zustand';

export const usePaymentStore = create((set, get) => ({
  // State
  isInitialized: false,
  isLoading: false,
  error: null,
  products: [],
  subscriptions: [],
  savedPaymentMethods: [],
  availableWallets: [],
  transactions: [],
  activeSubscriptions: [],
  currentTransaction: null,

  // Actions
  setLoading: (isLoading) => set({ isLoading }),
  setError: (error) => set({ error }),
  clearError: () => set({ error: null }),

  initialize: async (config) => {
    set({ isLoading: true, error: null });
    try {
      await encryptionService.initialize();
      await iapService.initialize();
      await stripeService.initialize(config.stripe);
      await digitalWalletService.initialize();
      await transactionManager.loadTransactionHistory();

      const availableWallets =
        await digitalWalletService.getAvailableWallets();
      const transactions = await transactionManager.getTransactionHistory({
        limit: 50,
      });

      set({
        isInitialized: true,
        isLoading: false,
        availableWallets,
        transactions,
      });
    } catch (error) {
      set({
        isLoading: false,
        error: {
          message: error.message,
          code: error.code || 'INIT_ERROR',
        },
      });
      throw error;
    }
  },

  loadProducts: async (productIds) => {
    set({ isLoading: true, error: null });
    try {
      const products = await iapService.loadProducts(productIds);
      set({ products, isLoading: false });
      return products;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  loadSubscriptions: async (subscriptionIds) => {
    set({ isLoading: true, error: null });
    try {
      const subscriptions =
        await iapService.loadSubscriptions(subscriptionIds);
      set({ subscriptions, isLoading: false });
      return subscriptions;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  purchaseProduct: async (productId, isConsumable = false) => {
    set({ isLoading: true, error: null });
    try {
      const purchase = await iapService.purchaseProduct(
        productId,
        isConsumable
      );

      const transaction = await transactionManager.recordTransaction({
        ...purchase,
        provider: PaymentProvider.IAP,
        status: TransactionStatus.COMPLETED,
        type: isConsumable
          ? ProductType.CONSUMABLE
          : ProductType.NON_CONSUMABLE,
      });

      set((state) => ({
        isLoading: false,
        transactions: [transaction, ...state.transactions],
        currentTransaction: transaction,
      }));

      return transaction;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  purchaseSubscription: async (subscriptionId, offerToken) => {
    set({ isLoading: true, error: null });
    try {
      const purchase = await iapService.purchaseSubscription(
        subscriptionId,
        offerToken
      );

      const transaction = await transactionManager.recordTransaction({
        ...purchase,
        provider: PaymentProvider.IAP,
        status: TransactionStatus.COMPLETED,
        type: ProductType.SUBSCRIPTION,
      });

      set((state) => ({
        isLoading: false,
        transactions: [transaction, ...state.transactions],
        activeSubscriptions: [
          ...state.activeSubscriptions,
          { subscriptionId, transactionId: transaction.id },
        ],
        currentTransaction: transaction,
      }));

      return transaction;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  processCardPayment: async (amount, currency, paymentMethodId) => {
    set({ isLoading: true, error: null });
    try {
      const paymentIntent = await stripeService.createPaymentIntent(
        amount,
        currency,
        { paymentMethodId }
      );

      const transaction = await transactionManager.recordTransaction({
        transactionId: paymentIntent.paymentIntentId,
        provider: PaymentProvider.STRIPE,
        status: TransactionStatus.PROCESSING,
        amount,
        currency,
        clientSecret: paymentIntent.clientSecret,
      });

      set((state) => ({
        isLoading: false,
        currentTransaction: transaction,
        transactions: [transaction, ...state.transactions],
      }));

      return { transaction, paymentIntent };
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  processWalletPayment: async (walletType, amount, currency) => {
    set({ isLoading: true, error: null });
    try {
      let result;

      if (walletType === PaymentProvider.APPLE_PAY) {
        result = await digitalWalletService.processApplePayPayment(
          amount,
          currency,
          'Your App'
        );
      } else if (walletType === PaymentProvider.GOOGLE_PAY) {
        result = await digitalWalletService.processGooglePayPayment(
          amount,
          currency
        );
      } else {
        throw new PaymentError('Unsupported wallet type', 'UNSUPPORTED_WALLET');
      }

      const transaction = await transactionManager.recordTransaction({
        ...result,
        type: 'WALLET_PAYMENT',
      });

      set((state) => ({
        isLoading: false,
        currentTransaction: transaction,
        transactions: [transaction, ...state.transactions],
      }));

      return transaction;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  restorePurchases: async () => {
    set({ isLoading: true, error: null });
    try {
      const purchases = await iapService.restorePurchases();
      set({ isLoading: false });
      return purchases;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  loadSavedPaymentMethods: async () => {
    set({ isLoading: true, error: null });
    try {
      const methods = await stripeService.getSavedPaymentMethods();
      set({ savedPaymentMethods: methods, isLoading: false });
      return methods;
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  deletePaymentMethod: async (paymentMethodId) => {
    set({ isLoading: true, error: null });
    try {
      await stripeService.deletePaymentMethod(paymentMethodId);
      set((state) => ({
        isLoading: false,
        savedPaymentMethods: state.savedPaymentMethods.filter(
          (pm) => pm.id !== paymentMethodId
        ),
      }));
    } catch (error) {
      set({
        isLoading: false,
        error: { message: error.message, code: error.code },
      });
      throw error;
    }
  },

  cleanup: async () => {
    await iapService.cleanup();
    set({
      isInitialized: false,
      products: [],
      subscriptions: [],
      savedPaymentMethods: [],
      availableWallets: [],
      currentTransaction: null,
    });
  },
}));

